import os
from flask import Flask, request, jsonify
from psycopg2 import connect

app = Flask(__name__)

# Set up database connection
db_host = os.environ['DB_HOST']
db_user = os.environ['DB_USER']
db_password = os.environ['DB_PASSWORD']
db_name = os.environ['DB_NAME']

def get_connection():
    return connect(
        host=db_host,
        user=db_user,
        password=db_password,
        dbname=db_name
    )

@app.route('/query', methods=['POST'])
def query():
    # Get table name and column names from request body
    table_name = request.json['table']
    columns = request.json['columns']

    # Build SQL query dynamically based on user input
    sql = f"SELECT {', '.join(columns)} FROM {table_name}"

    # Get filter conditions from request body
    filters = request.json['filters']

    # Add WHERE clause to SQL query if there are any filter conditions
    if filters:
        where_clause = 'WHERE ' + ' AND '.join([f"{k} {v}" for k, v in filters.items()])
        sql += f" {where_clause}"

    # Execute SQL query and get results
    with get_connection() as conn:
        cur = conn.cursor()
        cur.execute(sql)
        rows = cur.fetchall()

    # Return results in JSON format
    return jsonify(rows)